static inline ulong getenvsize (void)
{
	ulong rc = CONFIG_ENV_SIZE - sizeof (long);
#ifdef SUPPORT_ALI_HMAC
	rc -= sizeof(unsigned char) * HMAC_OUT_LENGTH;
#endif /*SUPPORT_ALI_HMAC*/

	if (HaveRedundEnv)
		rc -= sizeof (char);
#ifdef CONFIG_ENV_AES
	rc = rc & ~(16 - 1);
#endif
	return rc;
}


