/*
True:  use OTP key as aes key.
False: use input key as aes key.
*/
int sys_ic_adv_aes_key_is_enabled(uint8_t *hkey, uint8_t key_len)
{
	static uint32_t otp_value[4] = {0};
	static uint32_t otp_key_value[4] = {0};
	static uint32_t hkey_flag = 0;
	uint32_t chip_id = 0;
	aui_sys_get(AUI_SYS_GET_CHIP_ID, &chip_id);
	if((hkey == NULL) || (key_len<16))
		return -1;
	if((chip_id == ALI_C3505) || (chip_id == ALI_S3921))
	{
	if(hkey_flag == 0)
	{
			if(chip_id == ALI_C3505)
			{
	aui_otp_read(0x64*4, (uint8_t *)&otp_value[0], 16);
			}
			if(chip_id == ALI_S3921)
			{
				aui_otp_read(0xE8*4, (uint8_t *)&otp_value[0], 16);//S3921 :0xE8~0xEB
			}
			aui_otp_read(0x88*4, (uint8_t *)&otp_key_value[0], 16);
	//hkey_flag = 1;

	if((otp_value[0] == otp_value[2]) && (otp_value[1] == otp_value[3]))
		return -1;//empty key with OBF, maybe old prj
	memcpy(hkey, (uint8_t *)&otp_key_value[0], 16);
	return 1;
	}
	}
	return -1;

}


