{
	static unsigned long rl_chip_id = 0;
	unsigned long chip_id_t1 = 0;
	unsigned long chip_id_t2= 0;
#define OTP_DW_LEN  0x4

	if (0 == rl_chip_id) {
		if (AUI_RTN_SUCCESS != aui_otp_read(0, (unsigned char *)(&chip_id_t1), OTP_DW_LEN)) {
			return -1;
		}

		if (AUI_RTN_SUCCESS != aui_otp_read(0, (unsigned char *)(&chip_id_t2), OTP_DW_LEN)) {
			return -1;
		}

		if (chip_id_t1 == chip_id_t2) {
			rl_chip_id = chip_id_t1;
		}


#if 0
		if (0 == rl_chip_id) {
			return -1;
		}
#endif
	}

	if (NULL != pchipid) {
		*pchipid = rl_chip_id;
	}

	return 0;
}

static int env_aes_cbc_crypt(uint8_t * env, const int enc)
{
	aui_attr_dsc attr;
	aui_hdl hdl;

	dbg("ENV_SIZE:%d %s \n",ENV_SIZE, enc?"encypto":"de-crypto");
	memset(&attr, 0, sizeof(aui_attr_dsc));
	attr.uc_dev_idx = 0;
	attr.uc_algo = AUI_DSC_ALGO_AES;
	attr.dsc_data_type = AUI_DSC_DATA_PURE;
	attr.en_parity = AUI_DSC_PARITY_MODE_OTP_KEY_FROM_6C;
	if (aui_dsc_open(&attr, &hdl)) {
		printf("dsc open error\n");
		return -1;
	}

	/* clear key in EBC mode */
	attr.ul_key_pattern = AUI_DSC_KEY_PATTERN_SINGLE;
	attr.dsc_key_type   = AUI_DSC_CONTENT_KEY_OTP;
	attr.uc_mode        = AUI_DSC_WORK_MODE_IS_ECB;
	attr.en_residue     = AUI_DSC_RESIDUE_BLOCK_IS_NO_HANDLE;

	if (enc)
		attr.en_en_de_crypt = AUI_DSC_ENCRYPT;
	else
		attr.en_en_de_crypt = AUI_DSC_DECRYPT;

	if (aui_dsc_attach_key_info2dsc(hdl, &attr)) {
		printf("dsc attach key error\n");
		aui_dsc_close(hdl);
		return -1;
	}

	if (enc)
		aui_dsc_encrypt(hdl, env, env, ENV_SIZE);
	else
		aui_dsc_decrypt(hdl, env, env, ENV_SIZE);

	aui_dsc_close(hdl);
	return 0;
}
